sql:
SELECT COUNT(*)
FROM seminars
WHERE department_id = 1;

SELECT seminar_number, date, topic
FROM seminars
ORDER BY seminar_number ASC;

SELECT seminar_number, date
FROM seminars
ORDER BY seminar_number;

SELECT COUNT(speaker_id) AS total_speakers
FROM seminar_speakers
WHERE seminar_id = 1;

SELECT s.seminar_id, sf.average_rating
FROM seminars s
JOIN seminar_feedback sf ON s.seminar_id = sf.seminar_id;

SELECT seminar_id, AVG(average_rating) AS average_rating, SUM(total_responses) AS total_responses
FROM seminar_feedback
GROUP BY seminar_id;

external_knowledge:
- Highly-rated seminars refer to those seminars with an average rating greater than 4; 
- Experts are identified as speakers who hold a 'Ph.D.' qualification;
- The names of the seminars refer to their topics;
- Department details include the department name.

sql:
SELECT seminar_number
FROM seminars
ORDER BY seminar_number DESC;

external_knowledge:
- 'most popular seminars' refers to the seminars with the highest number of unique attendees;
- 'feedback score' is synonymous with 'rating' given by the attendees;
- 'largest crowds' implies ranking the seminars by the number of unique attendees in descending order and selecting the top 3.

sql:
SELECT AVG(average_rating) AS average_wave
FROM seminar_feedback
WHERE total_responses > 30;
